request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?modelId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "01e9c28ede6a4695b91dd90b3e0c5f1b") || CONTAINS(LCASE(STR(?modelName)), "01e9c28ede6a4695b91dd90b3e0c5f1b"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?originalId ?normalizedId ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model bbo:id ?modelId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?originalId)), "01e9c28ede6a4695b91dd90b3e0c5f1b") || 
         CONTAINS(LCASE(STR(?normalizedId)), "01e9c28ede6a4695b91dd90b3e0c5f1b") ||
         CONTAINS(LCASE(STR(?modelId)), "01e9c28ede6a4695b91dd90b3e0c5f1b"))
}
LIMIT 25
